def count_linear_ops(arr):
    ops = 0
    for _ in arr:
        ops += 1  # 每访问一个元素就记一次，模拟 O(n)
    return ops


def count_quadratic_ops(arr):
    ops = 0
    for _ in arr:
        for _ in arr:
            ops += 1  # 双层循环说明每个元素都和全部元素配对，模拟 O(n^2)
    return ops


nums = list(range(5))
print(count_linear_ops(nums))
print(count_quadratic_ops(nums))

def climb_stairs(n):
    if n <= 2:
        return n  # 小边界直接返回，避免后面转移越界

    dp = [0] * (n + 1)
    dp[1] = 1  # 到第 1 阶只有一种走法
    dp[2] = 2  # 到第 2 阶可以 1+1 或直接 2

    for i in range(3, n + 1):
        dp[i] = dp[i - 1] + dp[i - 2]  # 只从前一阶和前两阶转移，体现重叠子问题复用

    return dp[n]


print(climb_stairs(5))

from collections import deque


def bfs_shortest_hops(graph, start, target):
    queue = deque([(start, 0)])
    visited = {start}  # 一入队就标记，防止同一层被重复加入

    while queue:
        node, dist = queue.popleft()
        if node == target:
            return dist  # BFS 第一次到达目标时，边数已经最少

        for nei in graph.get(node, []):
            if nei not in visited:
                visited.add(nei)
                queue.append((nei, dist + 1))

    return -1


graph = {"A": ["B", "C"], "B": ["D"], "C": ["D"], "D": []}
print(bfs_shortest_hops(graph, "A", "D"))

class SimpleHashTable:
    def __init__(self, size=5):
        self.size = size
        self.buckets = [[] for _ in range(size)]  # 每个桶先用小列表模拟链地址法

    def _hash(self, key):
        return key % self.size  # 用最简单的模运算演示桶映射关系

    def put(self, key, value):
        idx = self._hash(key)
        bucket = self.buckets[idx]
        for i, (k, _) in enumerate(bucket):
            if k == key:
                bucket[i] = (key, value)  # 已存在就覆盖，保持 key 唯一
                return
        bucket.append((key, value))  # 冲突时挂到同一个桶后面

    def get(self, key):
        idx = self._hash(key)
        for k, v in self.buckets[idx]:
            if k == key:
                return v
        return None


ht = SimpleHashTable()
ht.put(13, "alice")
ht.put(18, "bob")
print(ht.get(18))

def lower_bound(nums, target):
    l, r = 0, len(nums) - 1
    ans = len(nums)  # 先假设不存在合法位置，便于统一处理

    while l <= r:
        mid = (l + r) // 2
        if nums[mid] >= target:
            ans = mid  # 当前 mid 合法，但还要继续向左找最早位置
            r = mid - 1
        else:
            l = mid + 1

    return ans


def two_sum_sorted(nums, target):
    l, r = 0, len(nums) - 1
    while l < r:
        s = nums[l] + nums[r]
        if s == target:
            return l, r
        if s < target:
            l += 1  # 和太小，只有增大左值才可能接近目标
        else:
            r -= 1  # 和太大，右值左移才能让总和下降
    return -1, -1


print(lower_bound([2, 4, 7, 9, 13, 18], 13))
print(two_sum_sorted([1, 2, 4, 6, 10], 8))
